import sailpoint.object.Identity;


String name= null;
if(null != value)
{
Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
name= id.getName();
}
}
return name;

import sailpoint.object.Identity;

String firstName= null;
if(null != value)
{

Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
firstName = id.getFirstname()!=null?id.getFirstname():id.getAttribute("firstname");

}
}
return firstName;

import sailpoint.object.Identity;

String lastname= null;
if(null != value)
{
Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
lastname = id.getLastname()!=null?id.getLastname():id.getAttribute("lastname");
}
}
return lastname;

  import sailpoint.object.Filter;
  import sailpoint.object.AuditEvent;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions;
  import java.text.SimpleDateFormat;
  import java.util.Date;

  String name= null;
  if(null != value)
  {
  Identity id = context.getObjectById(Identity.class, value);
  if(null != id)
  {
  name= id.getName();
  }
  }

  Date eventDate = renderCache.get("LeaverDate");
  long epochMillis = eventDate.getTime();

/* log.error("Epoch Time : " + epochMillis);
  log.error("renderCache :" +renderCache);
  log.error("column :" +column);
  log.error("scriptArgs :" +scriptArgs);
  log.error("eventdate :" +renderCache.get("LeaverDate"));*/

  QueryOptions qo = new QueryOptions();

  Filter filter = Filter.and(Filter.eq("target","Identity:"+name),Filter.eq("action", "identityLifecycleEvent"),Filter.eq("string1", "HR Source Lifecycle Event - Leaver"));
  qo.addFilter(filter);
  List events = context.getObjects(AuditEvent.class,qo);
  String eventname ="";

  if(events !=null && events.size()>0){
  eventname= events.get(0)!=null?events.get(0).getString1():"";
  }
  return eventname;
